using UnityEngine;
using System.Collections;

// DO NOT EDIT THIS FILE, IT'S NEEDED FOR BENCHMARKING, NOT PART OF THE OPTIMIZATION PRACTICE
public class BenchmarkCalibrator : MonoBehaviour
{
    public GameObject metalPrefab;
    public int batchSize = 50;
    public float targetFPS = 50f;
    public float spawnRange = 49f;

    private int currentMetals = 0;
    private bool calibrationComplete = false;
    

    void Start()
    {
        StartCoroutine(CalibrateHardware());
    }

    IEnumerator CalibrateHardware()
    {
        yield return new WaitForSeconds(1f);

        while (!calibrationComplete)
        {
            float currentFPS = 1f / Time.unscaledDeltaTime;

            if (currentFPS <= targetFPS && currentMetals > 0)
            {
                Debug.LogWarning("========== CALIBRATION COMPLETE ==========\nSet your totalMetals in GameManager to: " + currentMetals + "\n==========================================");
                calibrationComplete = true;
                
#if UNITY_EDITOR
                UnityEditor.EditorApplication.isPlaying = false;
#endif
                
                yield break;
            }

            for (int i = 0; i < batchSize; i++)
            {
                float randomX = Random.Range(-spawnRange, spawnRange);
                float randomZ = Random.Range(-spawnRange, spawnRange);
                Vector3 randomPos = new Vector3(randomX, 5f, randomZ);
                Instantiate(metalPrefab, randomPos, Quaternion.identity);
                currentMetals++;
            }

            yield return new WaitForSeconds(0.5f);
        }
    }
}